import json
import logging
from typing import Any, Dict, Optional

import requests

logger = logging.getLogger()
logger.setLevel(logging.INFO)


def fetch_url_content(
    url: str,
    method: str = "GET",
    *,
    headers: Optional[Dict[str, str]] = None,
    params: Optional[Dict[str, Any]] = None,
    data: Any = None,
    json_payload: Any = None,
    timeout: int = 10,
) -> Any:
    if not url:
        raise ValueError("URL must be provided")

    headers = headers or {}
    session = requests.Session()

    resp = session.request(
        method=method.upper(),
        url=url,
        headers=headers,
        params=params,
        data=data,
        json=json_payload,
        timeout=timeout,
    )
    resp.raise_for_status()

    ctype = resp.headers.get("Content-Type", "")
    if "application/json" in ctype:
        return resp.json()
    return resp.text


def lambda_handler(event: Dict[str, Any], _context: Any) -> Dict[str, Any]:
    """
    Generic AWS Lambda webhook processor that fetches remote content.
    The incoming `event` supports:
      - url:        target URL (required)
      - method:     HTTP method, default GET
      - headers:    request headers
      - params:     query parameters
      - data:       form/encoded body
      - json:       JSON body
    """
    try:
        url = event.get("url")
        method = event.get("method", "GET")
        headers = event.get("headers")
        params = event.get("params")
        data = event.get("data")
        json_payload = event.get("json")

        content = fetch_url_content(
            url,
            method=method,
            headers=headers,
            params=params,
            data=data,
            json_payload=json_payload,
        )

        logger.info("Fetched content from %s", url)

        return {
            "statusCode": 200,
            "body": json.dumps(
                {
                    "url": url,
                    "content": content,
                }
            ),
        }
    except Exception as exc:
        logger.exception("Error fetching content")
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "error": str(exc),
                }
            ),
        }